const data=$input.first().json;
const topics=(data.topic_list&&data.topic_list.topics)||[];
const mapped=topics.slice(0,30).map(t=>({ title:t.title, url:'https://community.n8n.io/t/'+(t.slug||'topic')+'/'+t.id, replies:t.posts_count }));
return [{ json: { topics: mapped } }];

const out=$input.first().json.output||{};
const m=Array.isArray(out.matches)?out.matches:[];
const rows=m.map(x=>'<li><a href="'+(x.url||'')+'">'+(x.title||'')+'</a><br/><b>Why:</b> '+(x.reason||'')+'<br/><b>Points:</b> '+(x.talking_points||'')+'</li>').join('');
const html=m.length?('<p>'+m.length+' forum question(s) match your expertise:</p><ul>'+rows+'</ul>'):'';
return [{ json: { count:m.length, hasMatches:m.length>0, subject:'n8n forum: '+m.length+' match your expertise', html } }];
